            }
          />
          <Field
            name="password"
            component={password =>
              <Input type={"password"} field={password} hintText={"Choose a password"} />
            }
          />
        </div>
      </div>
    );
  }

  renderButtons() {
    const { handleSubmit } = this.props
    const labelStyles = {
      textTransform: 'none',
      fontFamily: 'Open Sans',
      fontWeight: 600,
    };
    const styles = {
      color: '#fff',
      backgroundColor: '#099CEC',
