        <FlatButton
          label="Sign up"
          onClick={handleSubmit}
          style={styles}
          labelStyle={labelStyles}
        />
      </div>
    );
  }

  render() {
    const {
      handleSubmit,
    } = this.props;

    return (
      <div className='createFormContent'>
        <form onSubmit={handleSubmit}>
          {this.renderCreateUser()}
          {this.renderButtons()}
        </form>
      </div>
    );
  }
}

